import{_ as d,o as r,c as p,a2 as a}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"1964 年合伙人信：1963 年业绩回顾","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1964年/翻译.md","filePath":"01_letters/1964年/翻译.md"}'),h={name:"01_letters/1964年/翻译.md"};function e(l,t,o,i,n,s){return r(),p("div",null,[...t[0]||(t[0]=[a('<h1 id="_1964-年合伙人信-1963-年业绩回顾" tabindex="-1">1964 年合伙人信：1963 年业绩回顾 <a class="header-anchor" href="#_1964-年合伙人信-1963-年业绩回顾" aria-label="Permalink to &quot;1964 年合伙人信：1963 年业绩回顾&quot;">​</a></h1><h1 id="致1964年合伙人" tabindex="-1">致1964年合伙人 <a class="header-anchor" href="#致1964年合伙人" aria-label="Permalink to &quot;致1964年合伙人&quot;">​</a></h1><p>随信附上感恩节常规阅读材料：</p><ol><li><p>两份1964年修订版合伙协议。附通用条款的那份请您留存（与去年完全一致），另一份单页协议请签字、公证后寄回。奥马哈的合伙人可来我司办公室办理公证。</p></li><li><p>一份无价的准则手册——《基本规则》。我希望每位合伙人每年至少读一遍，这份材料将作为我11月信件的固定内容。除非您完全理解并从内心认同其中理念，否则请勿签署合伙协议。</p></li><li><p>两份1964年出资承诺书，一份自留，一份寄回。您可在12月31日午夜前随时修改承诺书内容，所以请尽早寄回；如需变更，只需写信或致电告知即可。</p></li></ol><p>所有提款将在1月1日后立即支付。您可提取100美元至全部权益的任意金额。同理，增资金额不限，需在1月10日前到账。若您有资产处置安排，此举可让您在1964年完成交易，享受税务优势。11月到账的增资视为预付款，按年利率6%计息至年末；12月到账的增资不计息。</p><p>1963年度完整税务信息将于1月25日前送达您手中。若在此之前需要税务预估，可告知我，我会提供大致数据。12月下旬我们还会发送一封简短的税务说明信。</p><p>截至10月底，道琼斯工业平均指数1963年涨幅为18.8%。我们在三大投资类别——普通股、套利、控股项目上均表现优异。约一个月前，我们成功出售了登普斯特农机制造公司的经营性资产。我将在年度信中详细讲述登普斯特的故事，或许会以《致哈里·博特尔颂》这样的抒情文字收尾。由于我们的收购价极具优势，登普斯特项目本身就有保底利润，而哈里凭借出色的工作，为我们带来了额外收益。顺便一提，哈里已预付资金，将成为1964年的有限合伙人——我们认为这只是开始，而非结束。</p><p>不过，1963年的业绩并非只靠登普斯特。尽管最后两个月市场仍有变数，中期业绩不宜过度解读，但截至10月底，合伙公司整体收益率约为32%。根据协议分配规则，扣除月度分红前，有限合伙人收益率为25.5%。我们约300万美元的收益中，超过200万美元来自有价证券，略低于100万美元来自登普斯特经营性资产。我们表现最佳的一只普通股与最佳套利项目的合计收益，与登普斯特经营性资产收益相当。</p><p>各位需知晓，若1963年最终业绩相对道指仍如10月31日般亮眼，我会将其视为异常年份。我认为长期来看，无法持续保持13.2个百分点的超额收益。只要每年能适度跑赢道指，就已令人满意。</p><p>诚挚的</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p><p>附：去年我们宣布，最晚寄回材料的合伙人不会获得奖励，今年政策不变。请尽快寄回协议与承诺书，避免我们临时手忙脚乱。如有任何需要，可致电比尔或我。谢谢！</p><p><a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>合伙有限公司</p><p>内布拉斯加州奥马哈市31区，基维特广场810号</p><h1 id="_1964年1月18日" tabindex="-1">1964年1月18日 <a class="header-anchor" href="#_1964年1月18日" aria-label="Permalink to &quot;1964年1月18日&quot;">​</a></h1><h2 id="_1963年业绩表现" tabindex="-1">1963年业绩表现 <a class="header-anchor" href="#_1963年业绩表现" aria-label="Permalink to &quot;1963年业绩表现&quot;">​</a></h2><p>1963年是出色的一年。并非因为我们实现了3,637,167美元的整体收益，或期初净资产收益率达38.7%（尽管这对务实的人来说很可喜），而是因为我们的业绩大幅跑赢核心基准——道琼斯工业平均指数（下称“道指”）。即便我们亏损20%而道指亏损30%，这封信依然会以“1963年是出色的一年”开篇。无论单年盈亏，只要长期能稳定跑赢道指，我们的长期结果——无论财务还是理念层面——都将令人满意。</p><p>为更新记录，下表汇总了合伙公司及其前身完整运营年度的道指表现、合伙公司整体业绩（分配给普通合伙人前）及有限合伙人收益：</p><table tabindex="0"><thead><tr><th>年份</th><th>道指整体收益(1)</th><th>合伙公司业绩(2)</th><th>有限合伙人收益(3)</th></tr></thead><tbody><tr><td>1957</td><td>-8.4%</td><td>10.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>38.5%</td><td>40.9%</td><td>32.2%</td></tr><tr><td>1959</td><td>20.0%</td><td>25.9%</td><td>20.9%</td></tr><tr><td>1960</td><td>-6.2%</td><td>22.8%</td><td>18.6%</td></tr><tr><td>1961</td><td>22.4%</td><td>45.9%</td><td>35.9%</td></tr><tr><td>1962</td><td>-7.6%</td><td>13.9%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.7%</td><td>38.7%</td><td>30.5%</td></tr><tr><td>(1) 基于道指年度市值变动加持有期间应得股息计算。</td><td></td><td></td><td></td></tr></tbody></table><p>(2) 1957-1961年为所有前身有限合伙企业全年合并业绩，扣除所有费用，未分配给合伙人及普通合伙人。</p><p>(3) 1957-1961年根据合伙公司业绩，按现行合伙协议分配给普通合伙人后计算。</p><p>有位幽默的有限合伙人建议我增加一列，显示普通合伙人收益——简单说，他也跑赢了道指。</p><p>下表为基于上述数据的累计/复利结果：</p><table tabindex="0"><thead><tr><th>年份</th><th>道指整体收益</th><th>合伙公司业绩</th><th>有限合伙人收益</th></tr></thead><tbody><tr><td>1957</td><td>-8.4%</td><td>10.4%</td><td>9.3%</td></tr><tr><td>1957-58</td><td>26.9%</td><td>55.6%</td><td>44.5%</td></tr><tr><td>1957-59</td><td>52.3%</td><td>95.9%</td><td>74.7%</td></tr><tr><td>1957-60</td><td>42.9%</td><td>140.6%</td><td>107.2%</td></tr><tr><td>1957-61</td><td>74.9%</td><td>251.0%</td><td>181.6%</td></tr><tr><td>1957-62</td><td>61.6%</td><td>299.8%</td><td>215.1%</td></tr><tr><td>1957-63</td><td>95.1%</td><td>454.5%</td><td>311.2%</td></tr><tr><td>年化复利</td><td>10.0%</td><td>27.7%</td><td>22.3%</td></tr><tr><td>我们似乎度过了七个丰收年。抱歉借用圣经典故，我们不会照搬约瑟夫的做法（我对诺亚的分散投资理念也从不热衷）。</td><td></td><td></td><td></td></tr></tbody></table><p>严肃来说，我必须强调：在我看来，我们上述17.7个百分点的道指超额收益，长期无法持续。每年跑赢道指10个百分点已是极佳成绩，即便超额收益更低，长期复利也会带来可观回报，后文会详述。这一判断（即便基于经验，也终归是预测）意味着：我们必须接受长期跑赢道指的幅度大幅收窄，且至少偶尔会有年份业绩逊于道指（甚至差距显著）。</p><p>上述观点在11月寄给各位的《基本规则》中已体现，但值得反复强调。</p><h2 id="投资公司对比" tabindex="-1">投资公司对比 <a class="header-anchor" href="#投资公司对比" aria-label="Permalink to &quot;投资公司对比&quot;">​</a></h2><p>我们定期将业绩与两家最大的股票型开放式投资公司（共同基金）、两家最大的多元化封闭式投资公司对比。这四家公司——马萨诸塞投资者信托、投资者股票基金、三大陆公司、雷曼公司，管理规模约40亿美元，代表了250亿美元投资公司行业的主流水平。我认为它们的业绩与绝大多数投资顾问机构大致相当，后者管理的资金规模更为庞大。</p><p>下表旨在说明，道指并非容易超越的投资业绩基准。仅这四家公司的投资顾问每年收取的费用就超700万美元，而这只是行业费用的一小部分。这些高薪专业人士的公开业绩显示，他们的表现略逊于道指。</p><p>我们的投资组合与运作模式与表中投资公司差异显著。但多数合伙人若不投资本合伙公司，大概率会选择业绩与这些投资公司相当的渠道，因此我认为它们是有意义的对比基准。</p><h3 id="年度业绩" tabindex="-1">年度业绩 <a class="header-anchor" href="#年度业绩" aria-label="Permalink to &quot;年度业绩&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>马萨诸塞投资者信托(1)</th><th>投资者股票基金(1)</th><th>雷曼公司(2)</th><th>三大陆公司(2)</th><th>道指</th><th>有限合伙人</th></tr></thead><tbody><tr><td>1957</td><td>-11.4%</td><td>-12.4%</td><td>-11.4%</td><td>-2.4%</td><td>-8.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>42.7%</td><td>47.5%</td><td>40.8%</td><td>33.2%</td><td>38.5%</td><td>32.2%</td></tr><tr><td>1959</td><td>9.0%</td><td>10.3%</td><td>8.1%</td><td>8.4%</td><td>20.0%</td><td>20.9%</td></tr><tr><td>1960</td><td>-1.0%</td><td>-0.6%</td><td>2.5%</td><td>2.8%</td><td>-6.2%</td><td>18.6%</td></tr><tr><td>1961</td><td>25.6%</td><td>24.9%</td><td>23.6%</td><td>22.5%</td><td>22.4%</td><td>35.9%</td></tr><tr><td>1962</td><td>-9.8%</td><td>-13.4%</td><td>-14.4%</td><td>-10.0%</td><td>-7.6%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.0%</td><td>16.5%</td><td>23.8%</td><td>19.5%</td><td>20.7%</td><td>30.5%</td></tr><tr><td>(1) 按资产净值变动加年度持有人分配计算。</td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><p>(2) 1957-1962年数据来自1963年《<a href="/03_companies/穆迪.html">穆迪</a>银行与金融手册》；1963年为预估数据。</p><h3 id="复利业绩" tabindex="-1">复利业绩 <a class="header-anchor" href="#复利业绩" aria-label="Permalink to &quot;复利业绩&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>马萨诸塞投资者信托</th><th>投资者股票基金</th><th>雷曼公司</th><th>三大陆公司</th><th>道指</th><th>有限合伙人</th></tr></thead><tbody><tr><td>1957</td><td>-11.4%</td><td>-12.4%</td><td>-11.4%</td><td>-2.4%</td><td>-8.4%</td><td>9.3%</td></tr><tr><td>1957-58</td><td>26.4%</td><td>29.2%</td><td>24.7%</td><td>30.0%</td><td>26.9%</td><td>44.5%</td></tr><tr><td>1957-59</td><td>37.8%</td><td>42.5%</td><td>34.8%</td><td>40.9%</td><td>52.3%</td><td>74.7%</td></tr><tr><td>1957-60</td><td>36.4%</td><td>41.6%</td><td>38.2%</td><td>44.8%</td><td>42.9%</td><td>107.2%</td></tr><tr><td>1957-61</td><td>71.3%</td><td>76.9%</td><td>70.8%</td><td>77.4%</td><td>74.9%</td><td>181.6%</td></tr><tr><td>1957-62</td><td>54.5%</td><td>53.2%</td><td>46.2%</td><td>59.7%</td><td>61.6%</td><td>215.1%</td></tr><tr><td>1957-63</td><td>85.4%</td><td>78.5%</td><td>81.0%</td><td>90.8%</td><td>95.1%</td><td>311.2%</td></tr><tr><td>年化复利</td><td>9.2%</td><td>8.6%</td><td>8.8%</td><td>9.7%</td><td>10.0%</td><td>22.3%</td></tr><tr><td>道指是被动指数，读者或许会觉得奇怪：华尔街顶尖专业人士竟难以超越甚至追平它。但事实确凿。而且，不能以“投资公司操作更保守”为借口。如上表及更多研究所示，这类机构的股票组合波动与道指同步。从下跌市表现来看，我们的操作远比投资公司的股票组合更保守。过往如此，未来却无保证。</td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><p>上述表述或许直白，但纯属事实陈述，绝非批评。在其制度框架与千亿资金管理规模下，它们只能取得这样的业绩。在框架内打破常规极为困难。因此，这类投资媒介的整体业绩必然与美国企业整体表现绑定。它们的价值，除少数特例外，不在于超额收益或更强的抗跌性，而在于操作便捷、无需自主决策、自动分散风险，最重要的是，能避免投资者陷入那些看似诱人实则低劣的投资手法。</p><h2 id="复利的魅力" tabindex="-1">复利的魅力 <a class="header-anchor" href="#复利的魅力" aria-label="Permalink to &quot;复利的魅力&quot;">​</a></h2><p>现在进入本文最激动人心的部分。去年，为强调复利的重要性，我调侃了伊莎贝拉女王及其财务顾问——他们竟做出投资发现新大陆这种低复利回报的决策。</p><p>复利话题略显俗气，我不妨借艺术提升格调：1540年，法国弗朗索瓦一世以4000埃居（约合2万美元）买下达芬奇《蒙娜丽莎》。倘若他脚踏实地，将这笔钱（及受托人）用于税后6%的投资，如今资产规模将超过1000万亿美元，是美国当前国债的3000多倍。我相信这足以终结家中关于“艺术品算不算投资”的争论。</p><p>正如我去年所言，此事另有启示：一是长寿的智慧，二是复利收益率微小变动带来的巨大影响。下表为10万美元在不同收益率下的复利收益：</p><table tabindex="0"><thead><tr><th>期限</th><th>4%</th><th>8%</th><th>12%</th><th>16%</th></tr></thead><tbody><tr><td>10年</td><td>48,024</td><td>115,892</td><td>210,584</td><td>341,143</td></tr><tr><td>20年</td><td>119,111</td><td>366,094</td><td>864,627</td><td>1,846,060</td></tr><tr><td>30年</td><td>224,337</td><td>906,260</td><td>2,895,970</td><td>8,484,940</td></tr><tr><td>显而易见，年化收益率几个百分点的差异，对投资计划的成功影响巨大，且期限越长效应越显著。只要<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>合伙公司能长期小幅跑赢主流投资媒介，就实现了其价值。</td><td></td><td></td><td></td><td></td></tr></tbody></table><p>或许有人失望，表中未出现第3页提到的22.3%收益率。该收益率为税前数据，税费由合伙人自行承担。即便忽略税费，超高利率长期复利也不现实。我认为，道指未来数十年难以维持过去七年的复利水平，且我们相对道指的超额收益也无法保持当前水准。基于这些假设，合伙公司未来年均复利收益率将显著低于过往。若在现有业绩中加入一次-30%的年份（道指对应-40%），数据将更符合长期预期。如上表所示，即便收益率降低，长期投资结果依然可观。</p><h2 id="我们的运作模式" tabindex="-1">我们的运作模式 <a class="header-anchor" href="#我们的运作模式" aria-label="Permalink to &quot;我们的运作模式&quot;">​</a></h2><p>此时我总会陷入文字分裂：一部分合伙人对业务细节感兴趣，另一部分则完全不懂，盼我赶紧收尾。</p><p>为兼顾双方，我简要介绍三大投资类别，感兴趣的读者可查阅附录案例。</p><p>三大类别长期预期收益无差异，我们希望每类资产10-15年都能实现跑赢道指10个百分点的目标。但单年表现差异极大，主要取决于当年市场环境。简要说明如下：</p><p><strong>“普通股”</strong>：基于量化标准判断的普遍低估股票，同时重视质化因素。通常无明确短期上涨信号，缺乏市场热度与资金追捧，核心优势是价格低廉——企业整体估值远低于谨慎分析得出的私人业主价值。我再次强调：量化是基础且必要，质化同样重要。我们青睐优质管理层、良好行业，以及沉寂管理层或股东群体的“变革潜力”，但<strong>价值是底线</strong>。该类别走势与道指高度同步，道指大跌时会大幅亏损，牛市中则表现最佳。长期来看，我们预期其能稳定跑赢道指。</p><p><strong>“套利”</strong>：有明确时间预期的证券，源于公司行为——出售、并购、重组、分拆等。我们不依据传言或内幕信息，只等待公开公告。风险主要不在于市场整体波动（虽有一定关联），而在于交易破裂：反垄断审查、股东否决、税务裁定不通过等。许多套利项目毛利润看似微薄，有朋友戏称是“捡别人剩下的最后五分钱”。但确定性高、持有期短，扣除偶发大额亏损后，年化收益可观。该类别年度收益比普通股更稳定，下跌市能大幅跑赢，牛市则拖累业绩。长期预期与普通股一致，能跑赢道指。</p><p><strong>“控股”</strong>：案例稀少，但一旦发生规模可观。除非初始就大额收购，否则控股均从普通股类别演变而来：当一只低估股票长期股价停滞，我们得以买入大量股份，获得企业控制权。之后是积极参与还是被动持股，取决于对公司未来与管理层能力的判断。近几个月我们大举买入的一只普通股，管理层优秀、策略合理，即便未来获得控股权，我们也大概率保持被动。</p><p>我们不会为了积极而积极，同等条件下更愿让他人管理。但为实现资本最优配置，必要时我们会主动介入。</p><p>无论主动或被动，控股项目必有保底利润，<strong>核心是收购价格足够低</strong>。获得控制权后，投资价值由企业价值决定，而非市场的非理性波动。</p><p>我们愿意且有能力获得控股权，让许多普通股投资拥有“双重保障”：若市场情绪好转，股价上涨；若不然，我们持续买入，直至通过企业价值验证判断。</p><p>控股项目业绩需按数年衡量，收购、优化管理、调整资本配置、出售或并购都需要时间，因此我们要求极高安全边际，收益不达标则放弃。</p><p>控股项目收购期走势与道指同步，后期则接近套利品种。</p><p>如我过往所言，组合在三类资产间的配置主要取决于机会可得性。因此，道指下跌年份，我们的配置偏向普通股还是套利，很大程度上靠运气，却会显著影响相对道指的业绩。这也是单年业绩无关紧要、无论好坏都不应过度解读的原因之一。</p><p>随着资产规模增长，我预期配置会向控股倾斜（目前占比最小）。这一判断可能错误，很大程度取决于未来市场走势。截至目前，我们大部分资金配置于普通股，套利次之，控股第三。</p><h2 id="其他事项" tabindex="-1">其他事项 <a class="header-anchor" href="#其他事项" aria-label="Permalink to &quot;其他事项&quot;">​</a></h2><p>年初我们的净资产为17,454,900美元。资产快速增长引发疑问：是否会稀释未来业绩？迄今为止，合伙公司规模与跑赢道指的幅度呈正相关，但不必过度解读。资金量大有时是优势，有时是劣势。我认为，即便资产规模为100万或500万美元，当前组合也无法优化。我们的投资想法总是比资金多10%，若情况改变，我会及时告知。</p><p>我与苏西在合伙公司的投资为2,392,900美元。今年我首次在月度分红外额外提款，只为满足国税局要求。</p><p>我与苏西还持有少量早年遗留的非流通证券（股东少于300人），总价值约为合伙权益的1%；此外，2060年买入一家本地公司的大额非流通持股，计划长期持有。除此之外，我们所有资产都投入合伙公司，未来也将如此。我无法承诺业绩，但能保证与各位共进退。此外，我的三位子女、父母、两位姐妹、两位连襟、岳父、四位阿姨、四位表亲、五位侄甥，直接或间接持有本合伙公司权益合计1,247,190美元。</p><p>比尔·斯科特与妻子也全力投入，持有237,400美元权益，占其净资产绝大部分。比尔工作出色，1964年多个重要项目的对接工作均由他主导。我也将大部分行政工作交给他，若我不在，有事可随时找比尔。</p><p>贝丝与唐娜承担着日益繁重的工作，表现出色。12月至1月，她们想必盼着换工作，却总能将堆积如山的事务处理得井井有条。</p><p>皮特·马威克·米切尔会计师事务所一如既往，高效完成严苛时间表下的审计工作。我们已指示他们今后每年对证券、现金等进行两次突击核查（往年为一次），成本不高，对金融机构而言十分必要。</p><p>一周内您将收到：</p><ol><li><p>税务说明信，包含1963年联邦所得税申报所需的全部合伙公司信息，此为唯一税务有效文件。</p></li><li><p>皮特·马威克·米切尔会计师事务所出具的1963年审计报告，说明合伙公司经营、财务状况及您的资本账户。</p></li><li><p>我签署的信件，列明1964年1月1日您在合伙公司的权益状况，数据与审计报告一致。</p></li><li><p>合伙协议附件A，列明所有合伙人名单。</p></li></ol><p>如有疑问请告知。随着公司规模扩大，信件遗漏、姓名写错、数字错位等错误概率增加，若发现问题请及时提醒。下一封信约在7月15日，汇总上半年业绩。</p><p>诚挚的</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p><hr><h1 id="附录" tabindex="-1">附录 <a class="header-anchor" href="#附录" aria-label="Permalink to &quot;附录&quot;">​</a></h1><h2 id="德克萨斯国家石油公司" tabindex="-1">德克萨斯国家石油公司 <a class="header-anchor" href="#德克萨斯国家石油公司" aria-label="Permalink to &quot;德克萨斯国家石油公司&quot;">​</a></h2><p>该项目是典型套利案例，源于近年最主要的套利来源——油气生产公司出售。</p><p>德克萨斯国家石油（TNP）是一家小型石油生产商，我多年来略有了解。</p><p>1962年初，我听闻其将出售给加州联合石油的传言。我从不会依据传言行动，但此次传言属实，若在传言阶段介入，收益会远高于公告后。但那是他人的做法，非我所为。</p><p>1962年4月初，交易基本条款公布。TNP发行三类证券：</p><ol><li><p>6.5%信用债券，赎回价104.25，交易完成前计息，完成后赎回。发行总额650万美元，我们在交易结束前买入26.4万美元本金。</p></li><li><p>约370万股普通股，高管与董事持有40%。委托书预估清算后每股收益7.42美元，我们在公告至收盘的六个月内买入64,035股。</p></li><li><p>65万份认股权证，行权价3.5美元/股。按普通股每股7.42美元的预估，权证价值3.92美元，我们六个月内买入83,200份，占总发行量约13%。</p></li></ol><p>股东否决风险为零，交易由控股股东协商，价格优厚。此类交易需产权核查、法律意见等，但风险几乎为零，无反垄断问题——当然这并非所有交易都如此。</p><p>唯一变数是税务裁定。加州联合石油采用标准<a href="/search.html?q=首都城市ABC">首都城市ABC</a>生产支付融资方式，南加州大学为支付方，因其慈善机构身份导致流程延迟。</p><p>这对国税局是新问题，但我们了解到南加州大学愿意放弃慈善身份，仍能通过银行贷款获得可观利润。问题虽导致延迟，却未威胁交易。</p><p>4月23-24日与公司沟通时，他们预估8-9月完成交易。5月9日邮寄的委托书称“交易将于1962年夏季完成，此后数月内将大部分收益分配给股东”，预估每股7.42美元。</p><p>比尔·斯科特出席5月29日休斯顿股东大会，公司仍预期9月1日收盘。</p><p>以下为后续与公司高管的电话沟通摘要：</p><ul><li><p>6月18日，秘书称：“加州联合石油已获悉国税局拟定有利裁定，待进一步审核，仍希望7月获批。”</p></li><li><p>7月24日，总裁称预期“下周初”获得税务裁定。</p></li><li><p>8月13日，财务主管告知TNP、加州联合石油、南加州大学人员均在华盛顿协商裁定。</p></li><li><p>9月18日，财务主管称：“暂无消息，国税局表示裁定下周可能完成。”</p></li></ul><p>每股收益预估仍为7.42美元。</p><p>9月下旬获得裁定，10月31日交易完成。11月13日我们的债券被赎回，随后将权证转为普通股，1962年12月14日、1963年2月4日、4月24日分别收到3.50美元、3.90美元、0.15美元分红，一两年后还将收到0.04美元。对147,235股（行权后）而言，每股4美分也意义重大。</p><p>这体现了套利的典型规律：(1) 交易耗时超预期；(2) 实际收益略高于预估。TNP项目多花了两个月，收益多了几个百分点。</p><p>TNP项目财务结果：</p><ol><li><p>债券投资260,773美元，持有期略低于五个月，获6.5%利息，实现资本利得14,446美元，年化总收益率约20%。</p></li><li><p>股票与权证实现资本利得89,304美元，当前剩余权益价值2,946美元。4月投资14.6万美元，10月持仓达73.1万美元，按资金占用时间计算，年化收益率约22%。</p></li></ol><p>两项均为全权益投资计算。我认为套利组合可适度使用杠杆，普通股则绝对禁止。</p><p>我们并非将TNP视为重大成功，套利项目有优有劣，这是我们常规操作的典型案例。我们尽力获取所有信息，持续跟进进展，结合经验评估。并非所有交易都参与，项目吸引力差异很大。套利失败会导致市值大幅缩水，因此不能频繁犯错，尽管我们偶尔难免失误。</p><h2 id="登普斯特农机制造公司" tabindex="-1">登普斯特农机制造公司 <a class="header-anchor" href="#登普斯特农机制造公司" aria-label="Permalink to &quot;登普斯特农机制造公司&quot;">​</a></h2><p>该项目1956年以普通股起步，当时股价18美元，账面价值72美元/股，其中扣除所有负债后流动资产50美元/股。公司过往盈利良好，当前仅盈亏平衡。</p><p>质化因素偏负面（行业艰难、管理层平庸），但量化数据极具吸引力。经验表明，买入100个此类标的，约70-80个能在1-3年内实现合理收益，具体触发因素难以预判，但整体预期乐观。</p><p>我们连续五年小幅加仓，期间我担任董事，对现有管理层的盈利前景愈发失望，但对资产与业务的了解加深，量化因素评估依然极佳。</p><p>1961年中，我们持有约30%股份（多次要约收购效果不佳），8-9月以30.25美元/股大额买入，叠加同价要约收购，持股比例超70%。过去五年收购价在16-25美元区间。</p><p>获得控制权后，我们提拔执行副总裁为总裁，观察其自主决策效果，结果不佳。1962年4月23日，我们聘请哈里·博特尔担任总裁。</p><p>哈里是该职位的完美人选，我此前已详述其成就，对比资产负债表更能直观体现资本重组效果：</p><table tabindex="0"><thead><tr><th>项目</th><th>1961年11月30日</th><th>1963年7月31日（未经审计）</th></tr></thead><tbody><tr><td>现金</td><td>166,000美元</td><td>89,000美元</td></tr><tr><td>美国政府证券（成本）</td><td>-</td><td>289,000美元</td></tr><tr><td>其他有价证券（成本，市值超成本）</td><td>-</td><td>2,049,000美元</td></tr><tr><td>现金及证券合计</td><td>166,000美元</td><td>2,436,000美元</td></tr><tr><td>应收账款（净额）</td><td>1,040,000美元</td><td>864,000美元</td></tr><tr><td>存货</td><td>4,203,000美元</td><td>890,000美元</td></tr><tr><td>预付费用等</td><td>82,000美元</td><td>12,000美元</td></tr><tr><td>流动资产合计</td><td>5,491,000美元</td><td>4,202,000美元</td></tr><tr><td>其他资产</td><td>45,000美元</td><td>62,000美元</td></tr><tr><td>厂房设备净额</td><td>1,383,000美元</td><td>862,000美元</td></tr><tr><td>资产总计</td><td>6,919,000美元</td><td>5,126,000美元</td></tr><tr><td>应付票据</td><td>1,230,000美元</td><td>-</td></tr><tr><td>其他负债</td><td>1,088,000美元</td><td>274,000美元</td></tr><tr><td>负债总计</td><td>2,318,000美元</td><td>274,000美元</td></tr><tr><td>净资产</td><td>4,601,000美元</td><td>4,852,000美元</td></tr><tr><td>负债与净资产总计</td><td>6,919,000美元</td><td>5,126,000美元</td></tr><tr><td>哈里的举措：</td><td></td><td></td></tr></tbody></table><ol><li><p>将存货从400多万美元（大量滞销）降至100万美元以下，大幅降低持有成本与跌价风险；</p></li><li><p>释放资金用于有价证券投资，获利超40万美元；</p></li><li><p>将管理与销售费用从每月15万美元降至7.5万美元；</p></li><li><p>将工厂制造费用从每直接工时6美元降至4.5美元；</p></li><li><p>关闭五家亏损分支机构（保留三家优质网点），替换为高效经销商；</p></li><li><p>解决内布拉斯加州哥伦布市辅助工厂的难题；</p></li><li><p>淘汰占用大量资金却无盈利的代销产品线，资金转投证券；</p></li><li><p>调整维修配件价格，几乎不损失销量的情况下，预计新增利润20万美元；</p></li></ol><p>最重要的是：</p><ol><li>通过上述及诸多其他措施，恢复与资本规模匹配的盈利能力。</li></ol><p>1963年，高额企业税（哈里快速用尽税收亏损抵免的速度超出我预期）叠加公司过剩流动资金，迫使我们要么注销法人资格，要么出售业务。</p><p>我们计划1963年底前完成二选一。注销法人资格虽有诸多问题，但能使合伙人收益翻倍，还能消除登普斯特证券的企业资本利得税。</p><p>在最后时刻，此前多次接近达成的交易破裂后，我们成功出售资产。尽管交易细节复杂，最终收益接近账面价值。叠加证券组合收益，我们实现约80美元/股的收益。登普斯特（现名第一比阿特丽斯公司，我们将品牌名出售给新公司）如今几乎全部为现金与有价证券。合伙公司年末审计中，我们的第一比阿特丽斯持股按资产价值（证券按市值）扣除20万美元或有负债准备金估值。</p><p>我认为买家会把登普斯特经营得很好，他们能力出众，有明确的业务扩张与盈利提升计划。我们原本也乐于以非公司形式运营登普斯特，但以合理价格出售也很满意。我们的业务是<strong>优质收购</strong>，而非天价出售。</p><p>哈里与我理念一致——看重高额激励。他目前是合伙公司有限合伙人，下一次成本优化项目，他仍是首选。</p><p>登普斯特的故事启示：</p><ol><li>我们的业务需要耐心，与热门高价股组合截然不同，在后者受追捧时期，我们或许显得保守。</li></ol><p>在买入期间，证券数月甚至数年股价停滞，对我们有利。这说明业绩需按足够周期衡量，我们建议<strong>至少三年</strong>。</p><ol><li>我们不能谈论当前投资操作。公开信息绝不会提升业绩，某些情况下还会严重损害利益。因此，若有人（包括合伙人）询问我们是否关注某只证券，我们只能拒绝回答。</li></ol><hr><h1 id="沃伦·巴菲特合伙有限公司" tabindex="-1"><a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>合伙有限公司 <a class="header-anchor" href="#沃伦·巴菲特合伙有限公司" aria-label="Permalink to &quot;[[沃伦·巴菲特]]合伙有限公司&quot;">​</a></h1><p>内布拉斯加州奥马哈市31区，基维特广场810号</p><p>1964年7月8日</p><h2 id="上半年业绩" tabindex="-1">上半年业绩 <a class="header-anchor" href="#上半年业绩" aria-label="Permalink to &quot;上半年业绩&quot;">​</a></h2><p>全家6月23日前往加州，因此这份报告提前至6月18日撰写。对按收信时间核对日程的合伙人，我保持常规时间顺序，部分空白由比尔在6月30日最终数据出炉后填补。</p><p>1964年上半年，道琼斯工业平均指数从762.95点升至831.50点，持有道指期间获股息约14.40点，上半年整体收益10.0%。截至6月18日撰写本文，我们的业绩与道指几乎无差异。我更希望报告的是：道指持平而我们盈利5%，或道指下跌10%而我们持平。但我一直强调，<strong>上涨市中我们跑赢道指的难度远大于震荡市或下跌市</strong>。</p><p>为更新记录，下表汇总道指表现、合伙公司整体业绩（分配给普通合伙人前）及有限合伙人收益：</p><table tabindex="0"><thead><tr><th>年份</th><th>道指整体收益(1)</th><th>合伙公司业绩(2)</th><th>有限合伙人收益(3)</th></tr></thead><tbody><tr><td>1957</td><td>-8.4%</td><td>10.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>38.5%</td><td>40.9%</td><td>32.2%</td></tr><tr><td>1959</td><td>20.0%</td><td>25.9%</td><td>20.9%</td></tr><tr><td>1960</td><td>-6.2%</td><td>22.8%</td><td>18.6%</td></tr><tr><td>1961</td><td>22.4%</td><td>45.9%</td><td>35.9%</td></tr><tr><td>1962</td><td>-7.6%</td><td>13.9%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.6%</td><td>38.7%</td><td>30.5%</td></tr><tr><td>1964年上半年</td><td>10.9%</td><td>12.0%</td><td>10.5%</td></tr><tr><td>累计收益</td><td>116.1%</td><td>521.0%</td><td>354.4%</td></tr><tr><td>年化复利</td><td>10.8%</td><td>27.6%</td><td>22.2%</td></tr><tr><td>上表脚注：</td><td></td><td></td><td></td></tr></tbody></table><p>(1) 基于道指年度市值变动加持有期间应得股息计算，包含合伙公司所有完整运营年度。</p><p>(2) 1957-1961年为所有前身有限合伙企业全年合并业绩，扣除所有费用，未分配给合伙人及普通合伙人。</p><p>(3) 1957-1961年根据合伙公司业绩，按现行合伙协议分配给普通合伙人后、有限合伙人月度分红前计算。</p><p>上半年买入操作令人满意，我认为<strong>买入环节占这项业务的90%</strong>。目前普通股类别包含三家公司，我们是其最大单一股东。这些股票的买入价远低于私人业主价值，其中一家已连续买入18个月，另外两家约一年。未来至少一年，甚至两年多，我们可能继续耐心每周买入。</p><p>我们最希望看到的情况是：公司盈利、资产价值等基本面大幅改善，但股价停滞，让我们持续加仓。这对短期业绩（尤其相对上涨市场）不利，却是长期利润的可靠来源。最终要么外部因素推动股价上涨，要么我们以低价获得控股权，两种结果我们都接受。</p><p>需明确的是，普通股类别大部分持仓仍为严重低估、但我们绝无可能获得控股权的证券。我们预期市场会在合理时间验证我们的分析，但这类标的没有上述“双重保障”。</p><h2 id="投资公司对比-1" tabindex="-1">投资公司对比 <a class="header-anchor" href="#投资公司对比-1" aria-label="Permalink to &quot;投资公司对比&quot;">​</a></h2><p>我们定期将业绩与两家最大的股票型开放式投资公司（共同基金）、两家最大的多元化封闭式投资公司对比。这四家公司——马萨诸塞投资者信托、投资者股票基金、三大陆公司、雷曼公司，管理规模超40亿美元，代表了280亿美元投资公司行业的主流水平。我认为它们的业绩与绝大多数投资顾问机构大致相当，后者管理的资金规模更为庞大。</p><table tabindex="0"><thead><tr><th>年份</th><th>马萨诸塞投资者信托(1)</th><th>投资者股票基金(1)</th><th>雷曼公司(2)</th><th>三大陆公司(2)</th><th>道指</th><th>有限合伙人</th></tr></thead><tbody><tr><td>1957</td><td>-11.4%</td><td>-12.4%</td><td>-11.4%</td><td>-2.4%</td><td>-8.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>42.7%</td><td>47.5%</td><td>40.8%</td><td>33.2%</td><td>38.5%</td><td>32.2%</td></tr><tr><td>1959</td><td>9.0%</td><td>10.3%</td><td>8.1%</td><td>8.4%</td><td>20.0%</td><td>20.9%</td></tr><tr><td>1960</td><td>-1.0%</td><td>-0.6%</td><td>2.5%</td><td>2.8%</td><td>-6.2%</td><td>18.6%</td></tr><tr><td>1961</td><td>25.6%</td><td>24.9%</td><td>23.6%</td><td>22.5%</td><td>22.4%</td><td>35.9%</td></tr><tr><td>1962</td><td>-9.8%</td><td>-13.4%</td><td>-14.4%</td><td>-10.0%</td><td>-7.6%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.0%</td><td>16.5%</td><td>23.7%</td><td>18.3%</td><td>20.6%</td><td>30.5%</td></tr><tr><td>1964年上半年</td><td>11.0%</td><td>9.5%</td><td>9.6%</td><td>8.6%</td><td>10.9%</td><td>10.5%</td></tr><tr><td>累计收益</td><td>105.8%</td><td>95.5%</td><td>98.2%</td><td>105.1%</td><td>116.1%</td><td>354.4%</td></tr><tr><td>年化复利</td><td>10.1%</td><td>9.4%</td><td>9.6%</td><td>10.1%</td><td>10.8%</td><td>22.2%</td></tr><tr><td>(1) 按资产净值变动加年度持有人分配计算。</td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><p>(2) 1957-1963年数据来自1964年《<a href="/03_companies/穆迪.html">穆迪</a>银行与金融手册》；1964年上半年为预估数据。</p><p>数据持续显示：薪酬最高、最受尊敬的投资管理机构，也难以追平被动<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>指数的业绩。这些公司的表现像池塘里的鸭子：水涨（市场涨）则鸭浮，水落则鸭沉。无论动物保护协会态度如何，鸭子只能为自己的行为负责，水位涨跌与它无关。市场水位对我们的业绩影响巨大，如上表所示，但我们偶尔也会“振翅高飞”。</p><p>我并非说道指是衡量股票投资业绩的唯一标准，但所有投资管理（包括自主管理）都应接受客观检验，标准应<strong>事前设定</strong>，而非事后挑选。</p><p>资金管理是庞大产业，投资管理者高度重视评估汽车、钢铁、化工等行业的公司管理层，投入大量精力、态度严肃，旨在识别优劣。但他们费力客观评估投资组合公司的管理层后，却不对自身进行类似检验，这十分奇怪。我们认为，投资者与投资管理者必须设定业绩标准，定期、客观审视自身业绩，如同审视投资标的。</p><p>我们将长期坚持这一原则。必须强调：设定业绩衡量标准不保证优秀结果，只保证客观评估。我再次强调《基本规则》中关于标准应用的要点：<strong>基于我们的运作模式，至少按三年周期评估</strong>；投机热潮期我们可能落后市场。但我可以承诺：我们初始用36英寸标尺，未来绝不更换。若不达标，我们不会换标尺。在我看来，整个投资管理行业（涉及数万亿美元）若都采用合理标尺、理性应用，运作会更高效。大多数人在自身业务中都会如此评估市场、人员、设备、方法，而资金管理是全球最大产业。</p><h2 id="税务" tabindex="-1">税务 <a class="header-anchor" href="#税务" aria-label="Permalink to &quot;税务&quot;">​</a></h2><p>年初我们持有2,991,090美元未实现收益，全部归属于1963年在任合伙人。截至6月30日，我们已实现资本利得2,826,248.76美元（96%为长期），因此今年很可能将1964年1月25日信中报告的、归属于您的未实现收益全部兑现。我再次强调：这与我们的实际业绩无关。即便我们有大额已实现收益，自1月1日起您的合伙权益市值也可能大幅缩水，因此无需为此狂喜；同理，已实现收益极少时也不必沮丧。我们不会为加速或延迟纳税而操作，投资决策基于对最优收益概率组合的判断。若意味着纳税，我很高兴长期资本利得税率足够低。</p><p>正如1964年4月1日最新税务信所述，1964年预估税按1963年实际税额缴纳最稳妥，此方式无罚款。</p><p>1月1日新入伙合伙人的税务负担适中，与往年新合伙人第一年情况一致，因为已实现资本利得先分配给持有未实现增值的老合伙人。这当然与经济业绩无关，所有有限合伙人（新老），除比尔·斯科特、露丝·斯科特、苏珊·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>（按合伙协议第五条）外，最终收益完全相同。与往年一样，目前所有合伙人的普通净收入微乎其微。</p><p>与往年一样，我们约11月1日向合伙人及有意入伙者发送信件，包含1965年合伙协议修订版、出资承诺书、1964年税务预估等。在此期间，夏季有任何疑问可找比尔解答。</p><p>诚挚的</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p><hr><h1 id="沃伦·巴菲特合伙有限公司-1" tabindex="-1"><a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>合伙有限公司 <a class="header-anchor" href="#沃伦·巴菲特合伙有限公司-1" aria-label="Permalink to &quot;[[沃伦·巴菲特]]合伙有限公司&quot;">​</a></h1><p>内布拉斯加州奥马哈市31区，基维特广场810号</p><p>1965年1月18日</p><h2 id="_1964年业绩表现" tabindex="-1">1964年业绩表现 <a class="header-anchor" href="#_1964年业绩表现" aria-label="Permalink to &quot;1964年业绩表现&quot;">​</a></h2><p>尽管1964年我们实现整体收益4,846,312.37美元，但以核心基准道琼斯工业平均指数（下称“道指”）衡量，这并非我们表现最好的一年。合伙公司整体收益27.8%，道指整体收益18.7%，有限合伙人收益22.3%。合伙公司9.1个百分点、有限合伙人3.6个百分点的超额收益，为1959年以来最低，1959年道指涨幅与今年相近。</p><p>但我并不沮丧。今年市场表现强劲，<strong>上涨市中我们跑赢道指的难度本就更大</strong>。我们注定会有被道指大幅跑赢的年份，某种程度上我庆幸不是今年。由于暴涨市场对我们不利，若1965年道指复制1964年表现，我们将难以追平，更别说大幅超越。</p><p>为更新记录，下表汇总道指表现、合伙公司整体业绩（分配给普通合伙人前）及有限合伙人收益：</p><table tabindex="0"><thead><tr><th>年份</th><th>道指整体收益(1)</th><th>合伙公司业绩(2)</th><th>有限合伙人收益(3)</th></tr></thead><tbody><tr><td>1957</td><td>-8.4%</td><td>10.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>38.5%</td><td>40.9%</td><td>32.2%</td></tr><tr><td>1959</td><td>20.0%</td><td>25.9%</td><td>20.9%</td></tr><tr><td>1960</td><td>-6.2%</td><td>22.8%</td><td>18.6%</td></tr><tr><td>1961</td><td>22.4%</td><td>45.9%</td><td>35.9%</td></tr><tr><td>1962</td><td>-7.6%</td><td>13.9%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.6%</td><td>38.7%</td><td>30.5%</td></tr><tr><td>1964</td><td>18.7%</td><td>27.8%</td><td>22.3%</td></tr><tr><td>(1) 基于道指年度市值变动加持有期间应得股息计算，包含合伙公司所有完整运营年度。</td><td></td><td></td><td></td></tr></tbody></table><p>(2) 1957-1961年为所有前身有限合伙企业全年合并业绩，扣除所有费用，未分配给合伙人及普通合伙人。</p><p>(3) 1957-1961年根据合伙公司业绩，按现行合伙协议分配给普通合伙人后、有限合伙人月度分红前计算。</p><p>累计/复利结果：</p><table tabindex="0"><thead><tr><th>年份</th><th>道指整体收益</th><th>合伙公司业绩</th><th>有限合伙人收益</th></tr></thead><tbody><tr><td>1957</td><td>-8.4%</td><td>10.4%</td><td>9.3%</td></tr><tr><td>1957-58</td><td>26.9%</td><td>55.6%</td><td>44.5%</td></tr><tr><td>1957-59</td><td>52.3%</td><td>95.9%</td><td>74.7%</td></tr><tr><td>1957-60</td><td>42.9%</td><td>140.9%</td><td>107.2%</td></tr><tr><td>1957-61</td><td>74.9%</td><td>251.0%</td><td>181.6%</td></tr><tr><td>1957-62</td><td>61.6%</td><td>299.8%</td><td>215.1%</td></tr><tr><td>1957-63</td><td>94.9%</td><td>454.5%</td><td>311.2%</td></tr><tr><td>1957-64</td><td>131.3%</td><td>608.7%</td><td>402.9%</td></tr><tr><td>年化复利</td><td>11.1%</td><td>27.7%</td><td>22.3%</td></tr></tbody></table><h2 id="投资公司对比-2" tabindex="-1">投资公司对比 <a class="header-anchor" href="#投资公司对比-2" aria-label="Permalink to &quot;投资公司对比&quot;">​</a></h2><p>我们定期将业绩与两家最大的股票型开放式投资公司（共同基金）、两家最大的多元化封闭式投资公司对比。这四家公司——马萨诸塞投资者信托、投资者股票基金、三大陆公司、雷曼公司，管理规模约45亿美元，股东约55万人，代表了300亿美元投资公司行业的主流水平。我认为它们的业绩与绝大多数投资顾问机构大致相当，后者管理的资金规模更为庞大。</p><p>下表旨在说明，道指并非容易超越的投资业绩基准。仅这四家公司的投资顾问每年收取的费用就超800万美元，而这只是专业投资管理行业费用的一小部分。这些高薪、广受尊敬的专业人士的公开业绩显示，表现略逊于被动指数道指。</p><h3 id="年度业绩-1" tabindex="-1">年度业绩 <a class="header-anchor" href="#年度业绩-1" aria-label="Permalink to &quot;年度业绩&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>马萨诸塞投资者信托(1)</th><th>投资者股票基金(1)</th><th>雷曼公司(2)</th><th>三大陆公司(2)</th><th>道指</th><th>有限合伙人</th></tr></thead><tbody><tr><td>1957</td><td>-11.4%</td><td>-12.4%</td><td>-11.4%</td><td>-2.4%</td><td>-8.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>42.7%</td><td>47.5%</td><td>40.8%</td><td>33.2%</td><td>38.5%</td><td>32.2%</td></tr><tr><td>1959</td><td>9.0%</td><td>10.3%</td><td>8.1%</td><td>8.4%</td><td>20.0%</td><td>20.9%</td></tr><tr><td>1960</td><td>-1.0%</td><td>-0.6%</td><td>2.5%</td><td>2.8%</td><td>-6.2%</td><td>18.6%</td></tr><tr><td>1961</td><td>25.6%</td><td>24.9%</td><td>23.6%</td><td>22.5%</td><td>22.4%</td><td>35.9%</td></tr><tr><td>1962</td><td>-9.8%</td><td>-13.4%</td><td>-14.4%</td><td>-10.0%</td><td>-7.6%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.0%</td><td>16.5%</td><td>23.7%</td><td>18.3%</td><td>20.6%</td><td>30.5%</td></tr><tr><td>1964</td><td>15.9%</td><td>14.3%</td><td>13.6%</td><td>12.6%</td><td>18.7%</td><td>22.3%</td></tr><tr><td>(1) 按资产净值变动加年度持有人分配计算。</td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><p>(2) 1957-1963年数据来自1964年《<a href="/03_companies/穆迪.html">穆迪</a>银行与金融手册》；1964年为预估数据。</p><h3 id="复利业绩-1" tabindex="-1">复利业绩 <a class="header-anchor" href="#复利业绩-1" aria-label="Permalink to &quot;复利业绩&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>马萨诸塞投资者信托</th><th>投资者股票基金</th><th>雷曼公司</th><th>三大陆公司</th><th>道指</th><th>有限合伙人</th></tr></thead><tbody><tr><td>1957</td><td>-11.4%</td><td>-12.4%</td><td>-11.4%</td><td>-2.4%</td><td>-8.4%</td><td>9.3%</td></tr><tr><td>1957-58</td><td>26.4%</td><td>29.2%</td><td>24.7%</td><td>30.0%</td><td>26.9%</td><td>44.5%</td></tr><tr><td>1957-59</td><td>37.8%</td><td>42.5%</td><td>34.8%</td><td>40.9%</td><td>52.3%</td><td>74.7%</td></tr><tr><td>1957-60</td><td>36.4%</td><td>41.6%</td><td>38.2%</td><td>44.8%</td><td>42.9%</td><td>107.2%</td></tr><tr><td>1957-61</td><td>71.3%</td><td>76.9%</td><td>70.8%</td><td>77.4%</td><td>74.9%</td><td>181.6%</td></tr><tr><td>1957-62</td><td>54.5%</td><td>53.2%</td><td>46.2%</td><td>59.7%</td><td>61.6%</td><td>215.1%</td></tr><tr><td>1957-63</td><td>85.4%</td><td>78.5%</td><td>80.8%</td><td>88.9%</td><td>94.9%</td><td>311.2%</td></tr><tr><td>1957-64</td><td>114.9%</td><td>104.0%</td><td>105.4%</td><td>112.7%</td><td>131.3%</td><td>402.9%</td></tr><tr><td>年化复利</td><td>10.0%</td><td>9.3%</td><td>9.4%</td><td>9.9%</td><td>11.1%</td><td>22.3%</td></tr><tr><td>反复列出这些表格，有合伙人问：为何这些聪明的管理者，拥有(1) 聪慧敬业的团队、(2) 几乎无限资源、(3) 广泛商业人脉、(4) 累计数百年投资经验，却会出现这样的结果？（后者让我想到一位求职者，称自己有20年经验，前雇主纠正为“1年经验重复20次”。）</td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><p>这个问题至关重要，本应成为投资管理者与大额投资者的研究重点，毕竟3000亿美元规模的每一个百分点，就是每年30亿美元。奇怪的是，华尔街文献几乎未探讨此问题，证券分析师协会会议、大会、研讨会等也鲜有讨论。我认为，任何投资管理机构的首要职责，是分析自身方法与业绩，再评判美国大型企业的管理能力与表现。</p><p>绝大多数情况下，无法超越甚至追平被动指数，绝非智力或诚信不足，而是源于：(1) 集体决策——我略带偏见地认为，任何规模的团队全员参与决策，都难以实现卓越投资管理；(2) 跟风效仿其他知名大型机构的策略与投资组合；(3) 制度框架下，平庸即“安全”，独立行动的个人回报与整体风险不匹配；(4) 坚持非理性的分散投资做法；最后也是最重要的：(5) 惰性。</p><p>上述评论或许不公，我们的统计对比也可能偏颇。我们的投资组合与运作模式与表中投资公司差异显著，但我相信我们与合伙人、它们与股东的目标一致：<strong>在持续股票投资的前提下，以最小永久损失风险，实现长期资本平均收益最大化</strong>。既然目标一致，且多数合伙人若不投资本合伙公司，大概率会选择业绩与这些投资公司相当的渠道，我认为它们的业绩记录对评估我们的表现有意义。</p><p>投资公司、投资顾问、信托部门等无疑为投资者提供重要服务：实现充分分散、保持长期视角、简化投资决策与操作，最重要的是，避免投资者陷入那些看似诱人实则低劣的投资手法。除少数特例外，这些机构并未明确承诺超额投资业绩，尽管公众可能从其宣传的“专业管理”中得出这样的推论。</p><p>我向合伙人承诺：正如我认为当前业绩对比有意义，未来无论结果如何，我都会坚持对比。相应地，若您认为该标准不相关，请现在提出异议，并建议其他<strong>事前</strong>而非事后适用的标准。</p><p>补充一点：我未在表中加入全球使用最广泛的投资顾问——“自我管理”。人们关注体重、高尔夫成绩、油费，却回避对自身投资管理能力的量化评估，尽管这关系到最重要的客户——自己。评估马萨诸塞投资者信托或雷曼公司的管理成就或许只是学术兴趣，客观评估实际管理您资金的人（哪怕是自己）的成就，却关乎真金白银。</p><h2 id="稳健性问题" tabindex="-1">稳健性问题 <a class="header-anchor" href="#稳健性问题" aria-label="Permalink to &quot;稳健性问题&quot;">​</a></h2><p>看到投资公司业绩表，有人可能会问：“没错，但这些公司的运作不是比合伙公司更稳健吗？”询问投资公司管理层，他们会坦诚回答更稳健；询问遇到的前100位证券分析师，绝大多数也会认同。我却不认同。我90%以上的净资产投入本合伙公司，家人持股比例也很高，但这仅证明我态度真诚，而非观点正确。</p><p>毫无疑问，投资公司的投资方式比我们更传统。对许多人而言，传统等同于稳健。在我看来，这是错误认知。<strong>传统或非常规本身，都不代表稳健</strong>。</p><p>真正稳健的行为源于<strong>合理假设、准确事实、严谨推理</strong>。这些特质可能导向传统做法，也可能多次导向非传统。世界某个角落，可能仍有地平说协会定期聚会。</p><p>我们不会因重要人物、发声者或多数人认同而安心，也不会因他们反对而不安。民意调查无法替代思考。当我们遇到能理解、事实清晰、行动路径明确的情况时，无论传统或非常规、他人认同或反对，我们都认为自己在以稳健的方式前进。</p><p>上述表述或许非常主观，您应偏好客观方法，我也是。我建议评估过往策略稳健性的合理方式之一，是研究<strong>下跌市业绩</strong>。我们表中仅有三年下跌市，遗憾的是（仅为测试目的）跌幅均温和。这三年里，我们的投资业绩显著优于任何传统组合。</p><p>具体而言，若这三年连续发生，累计结果为：</p><ul><li><p>三大陆公司：-9.7%</p></li><li><p>道指：-20.6%</p></li><li><p>马萨诸塞投资者信托：-20.9%</p></li><li><p>雷曼公司：-22.3%</p></li><li><p>投资者股票基金：-24.6%</p></li><li><p>有限合伙人：+45.0%</p></li></ul><p>我们不认为这一对比至关重要，但确有参考意义。我们认为，这比“我们持有（无论价格）AT&amp;T、通用电气、<a href="/03_companies/IBM.html">IBM</a>、通用汽车，因此很稳健”更有意义。无论如何，评估任何投资计划或管理（包括自主管理）的稳健性，都应基于理性客观标准，我建议<strong>下跌市业绩</strong>是至少一项有意义的测试。</p><h2 id="复利的魅力-1" tabindex="-1">复利的魅力 <a class="header-anchor" href="#复利的魅力-1" aria-label="Permalink to &quot;复利的魅力&quot;">​</a></h2><p>早期年度信的读者对仅罗列当期投资经历不满，渴望跨越数百年的投资策略深度研究带来的智力启发。因此，设立本章节。</p><p>我们前两次探究金融专家的神话，发现伊莎贝拉（资助哥伦布航行）、弗朗索瓦一世（最初购买《蒙娜丽莎》）所谓的精明投资，在财务上近乎愚蠢。为这些人辩护的人提出了大量感性琐碎理由，但我们的复利表格从未被撼动。</p><p>然而，有一项批评让我有些在意：有人称本专栏语气负面，只评论历史上的金融无能者。他们挑战我，要求记录一个彰显金融睿智、成为后世标杆的故事。</p><p>有一个故事脱颖而出：1626年，曼哈顿印第安人将岛屿卖给挥霍无度的彼得·米纽伊特，净得24美元。米纽伊特获得22.3平方英里土地，约合621,688,320平方英尺。参考可比交易，难以精确评估，每平方英尺20美元的估值看似合理，岛屿当前土地价值约124.337664亿美元（125亿美元）。新手或许觉得这笔交易不错。但印第安人只需实现6.5%的年化收益率（部落共同基金代表本可承诺），就能完胜米纽伊特。按6.5%计算，24美元338年后变为421.057728亿美元；若能多赚0.5个百分点达到7%，现值将达2050亿美元。</p><p>言尽于此。</p><p>部分合伙人的投资期限可能更短，为方便您，我们列出10万美元在不同收益率下的复利收益：</p><table tabindex="0"><thead><tr><th>期限</th><th>4%</th><th>8%</th><th>12%</th><th>16%</th></tr></thead><tbody><tr><td>10年</td><td>48,024</td><td>115,892</td><td>210,584</td><td>341,143</td></tr><tr><td>20年</td><td>119,111</td><td>366,094</td><td>864,627</td><td>1,846,060</td></tr><tr><td>30年</td><td>224,337</td><td>906,260</td><td>2,895,970</td><td>8,484,940</td></tr><tr><td>本表显示了以下因素的财务优势：</td><td></td><td></td><td></td><td></td></tr></tbody></table><ol><li><p>长寿（金融专家术语称为“玛士撒拉策略”）</p></li><li><p>高复利收益率</p></li><li><p>两者结合（作者特别推荐）</p></li></ol><p>显而易见，年化收益率微小提升带来的收益巨大。这解释了我们的态度：我们希望大幅超越平均投资收益，但也认为<strong>每一个百分点的超额收益都有实际价值</strong>。</p><h2 id="我们的目标" tabindex="-1">我们的目标 <a class="header-anchor" href="#我们的目标" aria-label="Permalink to &quot;我们的目标&quot;">​</a></h2><p>您会发现，上表未列入合伙公司八年平均27.7%、有限合伙人平均22.3%的收益率。长期来看，这样的数字不现实，原因有三（不必担心我“刻意保守”以验证预言）：</p><ol><li><p>巨额资金以如此高利率复利，规模会迅速达到国债级别。</p></li><li><p>八年历史中，证券整体重估带来的普通股市场年均整体收益率，我认为未来数十年无法实现。未来20-30年，我预期道指年均整体收益约6%-7%，而非过往的11.1%。仅此一项，就会使我们的年化复利收益率降低约4个百分点。道指只需1965年下跌20.5%，九年平均就会降至7%。股票投资者必然会遇到此类年份（甚至更糟）。若股票持仓（如本合伙公司）市值下跌20%-30%会导致情绪或财务困境，您应完全避免股票类投资。用诗人哈里·杜鲁门的话说：“受不了热，就别进厨房。”当然，最好在进入“厨房”前考虑清楚。</p></li><li><p>我们认为，长期无法维持合伙公司相对道指16.6个百分点、有限合伙人11.2个百分点的超额收益。我们已连续八年跑赢道指，尽管利润分配安排使有限合伙人有一年收益略低于道指。我们注定会有多年份（复数）合伙公司业绩逊于道指，即便普通合伙人痛心疾首（希望有限合伙人不必如此）。届时，我们的平均超额收益会大幅下降。我认为我们未来仍会有多年份实现可观超额收益，但迄今为止，我们从未经历真正平庸（甚至更糟）的年份，这显然无法永久持续。</p></li></ol><p>那么我们预期能实现什么？当然，我的说法大多是猜测，受自身利益、自负等因素影响较大。了解金融史的人都知道，此类猜测误差极大。或许本不该写入信中，但这是合伙人频繁且合理提出的问题。长期预期收益是我们所有合伙人的核心考量，我理应明确说明，即便日后可能显得愚蠢。我秉持严谨观点：任何投资管理者，无论作为经纪人、投资顾问、信托部门、投资公司等，都应明确说明试图实现的目标，以及衡量目标达成程度的标准。</p><p>我希望长期业绩按以下路径发展：</p><ol><li><p>道指整体收益（含股息）年均约7%，波动幅度极大——极端情况约-40%至+50%，多数年份在-10%至+20%区间；</p></li><li><p>合伙公司分配给普通合伙人前，年均跑赢道指10个百分点——超额收益波动同样极大，差年份可能跑输道指10个百分点，顺年份可能跑赢25个百分点；</p></li><li><p>基于上述假设，合伙公司年均收益约17%，有限合伙人约14%。该数据年度波动极大，最终幅度取决于上述(1)(2)的极端情况相互作用。</p></li></ol><p>我必须强调，以上纯属推测，可能受自身利益、自负等因素影响。了解金融史的人都知道，此类猜测误差极大。</p><h2 id="我们的运作模式-1" tabindex="-1">我们的运作模式 <a class="header-anchor" href="#我们的运作模式-1" aria-label="Permalink to &quot;我们的运作模式&quot;">​</a></h2><p>过往年度信中，我一直用三种类别描述投资操作。现在我认为分为四类更合适。新增“相对低估普通股”类别，部分反映了我对普通股类别中一直存在的本质差异的进一步思考，部分反映了这一曾经极小的子类别如今已成为组合重要部分，且迄今业绩优异，值得投入大量时间寻找更多机会。最后，部分反映了我们为提升该类别预期收益与稳定性，开发并实施了一种全新的独特投资技巧。因此，我们当前四大类别为：</p><ol><li><strong>“私人业主视角普通股”</strong>：基于量化标准判断的普遍低估股票，同时重视质化因素。通常无明确短期上涨信号，缺乏市场热度与资金追捧，核心优势是价格低廉——企业整体估值远低于谨慎分析得出的私人业主价值。我再次强调：量化是基础且必要，质化同样重要。我们青睐优质管理层、良好行业，以及沉寂管理层或股东群体的“变革潜力”，但<strong>价值是底线</strong>。</li></ol><p>很多时候，该类别拥有理想的“双重保障”：要么外部因素推动股价上涨，要么以低价获得企业控股权。绝大多数情况是前者，后者是多数投资操作不具备的安全垫。我们持续增持1964年中期报告中提到的三家公司，我们是其最大单一股东。这三家公司基本面价值均以可观速度提升，其中两家我们完全被动，第三家仅轻微参与。未来我们极不可能深度参与任何一家的决策，但必要时我们会做好准备。</p><ol><li><strong>“相对低估普通股”</strong>：与同品质证券相比，价格相对低廉的证券。我们要求估值存在显著差异，但（通常因规模较大）认为私人业主价值概念不适用。该类别关键是<strong>同类对比</strong>，我们为此付出大量努力。绝大多数情况下，我们对行业或公司了解不足，无法做出合理判断——此时我们选择放弃。</li></ol><p>如前所述，这一新类别规模不断扩大，业绩优异。我们近期开始实施一种技巧，有望大幅降低整体估值标准变动带来的风险；例如：我们以12倍市盈率买入某股票，而同等或更低品质公司市盈率为20倍，若随后市场重估，后者市盈率降至10倍。</p><p>这种风险一直让我极为担忧，因为相比“私人业主视角普通股”或“套利”，我们会陷入被动。风险降低后，我们认为该类别前景广阔。</p><ol><li><p><strong>“套利”</strong>：有明确时间预期的证券，源于公司行为——出售、并购、重组、分拆等。我们不依据传言或内幕信息，只等待公开公告。风险主要不在于市场整体波动（虽有一定关联），而在于交易破裂：反垄断审查、股东否决、税务裁定不通过等。许多套利项目毛利润看似微薄，有点像找还有剩余时间的停车计时器。但确定性高、持有期短，扣除偶发大额亏损后，年化平均收益可观。该类别年度收益比普通股更稳定，下跌市能大幅跑赢，牛市则拖累业绩。长期预期与普通股一致，能跑赢道指。</p></li><li><p><strong>“控股”</strong>：案例稀少，但一旦发生规模可观。除非初始就大额收购，否则控股均从“私人业主视角普通股”类别演变而来：当一只低估股票长期股价停滞，我们得以买入大量股份，获得企业控制权。之后是积极参与还是被动持股，取决于对公司未来与管理层能力的判断。</p></li></ol><p>我们不会为了积极而积极，同等条件下更愿让他人管理。但为实现资本最优配置，必要时我们会主动介入。</p><p>无论主动或被动，控股项目必有保底利润，<strong>核心是收购价格足够低</strong>。获得控制权后，投资价值由企业价值决定，而非市场的非理性波动。</p><p>“私人业主视角普通股”下提到的三家我们是最大股东的公司，凭借“双重保障”，任何一家都可能转为控股项目，我们乐于接受；若股价上涨至内在价值合理水平，我们卖出完成优质普通股操作，也同样满意。</p><p>控股项目业绩需按数年衡量，收购、优化管理、调整资本配置、出售或并购都需要时间，因此我们要求极高安全边际，收益不达标则放弃。</p><p>控股项目收购期走势与道指同步，后期则接近套利品种。</p><p>您或许有兴趣知道，我们此前的控股项目登普斯特农机制造公司的买家，似乎经营得非常好，符合我们的预期，也让我们满意。依赖最终买家犯错的投资操作（华尔街称为“博傻理论”）极不稳定。以真正低价买入，只需正常处置就能获得满意结果，这才更稳妥。</p><p>如我过往所言，组合在四类资产间的配置主要取决于机会可得性。因此，单年配置偏向普通股、套利还是控股，很大程度上靠运气，这一多变因素会显著影响我们相对道指的业绩。这也是单年业绩无关紧要、无论好坏都不应过度解读的原因之一。</p><p>举例说明类别配置的重要性：过去三年，采用与衡量合伙公司整体业绩完全不同的计算方法（按类别月度平均市值投资、剔除杠杆与办公费用等，此方法最适合类别间对比，但不反映合伙公司整体业绩），普通股（合并当前两类）、套利与道指表现如下：</p><table tabindex="0"><thead><tr><th>年份</th><th>普通股</th><th>套利</th><th>道指</th></tr></thead><tbody><tr><td>1962</td><td>-1.0%</td><td>14.6%</td><td>-8.6%</td></tr><tr><td>1963</td><td>20.5%</td><td>30.6%</td><td>18.4%</td></tr><tr><td>1964</td><td>27.8%</td><td>10.3%</td><td>16.7%</td></tr><tr><td>显而易见，1962年套利（与控股）拯救了业绩，若当年该类别配置较轻，最终结果会差很多，尽管考虑到当年市场环境仍相当可观。我们当年套利配置比例本可能低得多，是机会决定了配置，而非我对市场走势的判断。因此，必须承认1962年我们在类别配置上运气极佳。</td><td></td><td></td><td></td></tr></tbody></table><p>1963年我们有一个极佳的套利项目，极大影响业绩，普通股表现也不错，造就了辉煌一年。若套利表现正常（更接近1962年），我们相对道指的表现会差很多。这一年并非配置帮了我们，而是项目本身优质。</p><p>最后，1964年套利严重拖累业绩。在道指大涨年份，这属于正常情况，且表现比预期更差，因项目平庸。事后看来，全部配置普通股会更理想，但我们不会按事后诸葛亮的方式操作。</p><p>我希望上表能让大家明白：单年业绩受诸多变量影响，部分变量我们难以控制或预判。我们认为所有类别都是优质业务，很高兴拥有多个类别而非单一依赖，这让我们在每个类别内更有选择性，降低因单一类别机会消失而完全无法操作的风险。</p><h2 id="税务-1" tabindex="-1">税务 <a class="header-anchor" href="#税务-1" aria-label="Permalink to &quot;税务&quot;">​</a></h2><p>今年合伙人对税务负担怨声载道。当然，即便税务单空白，也可能有人抱怨。</p><p>相当多聪明的人，因“税务考量”犯下投资错误，可能比其他任何原因都多。我的一位朋友——加州著名哲学家认为，人生大多数错误源于忘记真正的目标。当税务这种情绪性极强的因素介入时，情况尤其如此（我还有一位朋友——东岸著名哲学家说，他在意的不是无代表权征税，而是征税本身）。</p><p>回到加州哲学家的观点：投资的真正目标是什么？不是缴纳最少的税，尽管这是实现目标的考虑因素之一。手段与目标不可混淆，目标是<strong>实现最大税后复利收益率</strong>。显然，若两种方案税前复利收益率相等，一种需纳税、一种无需，后者更优。但我们很少遇到这种情况。</p><p>从3000只股票中选出的</p>',218)])])}const u=d(h,[["render",e]]);export{c as __pageData,u as default};
